                ),
                OverviewCountRow::new(
                    MODULE_HEDR_UNKNOWN_LABEL,
                    counts.hedr_unknown,
                    non_zero_error_or_neutral(counts.hedr_unknown),
                ),
            ],
            actions: Vec::new(),
        }
    }

    /// Creates a module panel by counting supplied module records.
