            rows: vec![
                OverviewCountRow::limited(MODULE_FULL_LABEL, counts.full, MAX_MODULES_FULL),
                OverviewCountRow::limited(MODULE_LIGHT_LABEL, counts.light, MAX_MODULES_LIGHT),
                OverviewCountRow::limited(
