        match self {
            Self::OverviewIssues => "Overview Issues",
            Self::Errors => "Errors",
            Self::WrongFormat => "Wrong File Formats",
            Self::LoosePrevis => "Loose Previs",
            Self::JunkFiles => "Junk Files",
            Self::ProblemOverrides => "Problem Overrides",
            Self::RaceSubgraphs => "Race Subgraphs",
        }
