            Self::OverviewIssues => settings.overview_issues,
            Self::Errors => settings.errors,
            Self::WrongFormat => settings.wrong_format,
            Self::LoosePrevis => settings.loose_previs,
            Self::JunkFiles => settings.junk_files,
